let cachedStatus = null;
let startTime = null;
let cachedUserId = null;

return (chargingId) => {
  if (cachedStatus === null) {
    const statuses = ['idle', 'working', 'error'];
    cachedStatus = statuses[Math.floor(Math.random() * statuses.length)];

    // 生成随机8位用户ID并持久缓存
    cachedUserId = String(Math.floor(Math.random() * 90000000) + 10000000);

    if (cachedStatus === 'working') {
      // 过去8小时内的一个随机时间点（时间戳）
      const eightHoursMs = 8 * 60 * 60 * 1000;
      startTime = Date.now() - Math.floor(Math.random() * eightHoursMs);
    }
  }

  let duration = null;
  let kwh = null;

  if (cachedStatus === 'working' && startTime !== null) {
    const now = Date.now();
    const diffMs = now - startTime;
    const totalSeconds = Math.floor(diffMs / 1000);
    const hours = Math.floor(totalSeconds / 3600);
    const minutes = Math.floor((totalSeconds % 3600) / 60);
    const seconds = totalSeconds % 60;

    duration = [
      String(hours).padStart(2, '0'),
      String(minutes).padStart(2, '0'),
      String(seconds).padStart(2, '0')
    ].join(':');

    const durationHours = diffMs / (1000 * 60 * 60);
    kwh = parseFloat((durationHours * 0.82).toFixed(2));
  }

  return {
    status: cachedStatus,
    duration: duration,
    kwh: kwh,
    userId: cachedUserId
  };
};

